						bestPlacement.deltaCost = delta
						bestPlacement.valid = true
					}
				}
				dispatch.Assigns[i].RemoveShip(shipID)
				dispatch.Assigns[i].GenRoute()
			}
			checkedSlots[i] = true
		}
		if !bestPlacement.valid && dispatch.AssignsLen < MAXASSIGNS {
