	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	type cand struct {
		idx       int
		costDelta float64
		feasible  bool
	}
	for oi := 0; oi < orderCount; oi++ {
		ori, des := oris[oi], dess[oi]
		bestCands := make([]cand, 0, MAXASSIGNS)
		for ai := 0; ai < MAXASSIGNS; ai++ {
			var assign Assign
			if ai < dispatch.AssignsLen {
				assign = dispatch.Assigns[ai]
			} else if ai == dispatch.AssignsLen {
				assign = Assign{}
			} else {
				continue
			}
			prevCost := assign.Cost
			success := assign.AddShip(total_ship+oi, ori, des)
			if !success {
				assign.RemoveShip(total_ship + oi)
				bestCands = append(bestCands, cand{idx: ai, costDelta: 0, feasible: false})
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			delta := newCost - prevCost
			if newCost >= 0 && delta >= 0 {
				bestCands = append(bestCands, cand{idx: ai, costDelta: delta, feasible: true})
			} else {
				assign.RemoveShip(total_ship + oi)
				assign.GenRoute()
				bestCands = append(bestCands, cand{idx: ai, costDelta: 0, feasible: false})
			}
		}
		selectedIdx := -1
		minFeasibleDelta := 1e308
		for _, c := range bestCands {
